param(
    [string]$Root = ""
)

$ErrorActionPreference = "Stop"

if (-not $Root) {
    $Root = Split-Path -Parent $PSScriptRoot
}

$scriptRoot = Join-Path $Root "scripts"
if (-not (Test-Path -LiteralPath $scriptRoot)) {
    throw "Missing scripts directory: $scriptRoot"
}

$scripts = @(Get-ChildItem -LiteralPath $scriptRoot -Filter "*.ps1" -File | Sort-Object Name)
$parseErrors = @()
foreach ($script in $scripts) {
    $tokens = $null
    $errors = $null
    [System.Management.Automation.Language.Parser]::ParseFile($script.FullName, [ref]$tokens, [ref]$errors) | Out-Null
    foreach ($error in $errors) {
        $parseErrors += [pscustomobject]@{
            File = $script.FullName
            Line = $error.Extent.StartLineNumber
            Message = $error.Message
        }
    }
}
if ($parseErrors.Count -gt 0) {
    $parseErrors | Format-Table -AutoSize | Out-String | Write-Output
    throw "PowerShell parse errors found"
}

function Require-Text {
    param(
        [string]$Path,
        [string]$Text,
        [string]$Reason
    )

    $content = Get-Content -LiteralPath $Path -Raw
    if (-not $content.Contains($Text)) {
        throw "Missing required launch safety text in $Path`: $Reason"
    }
}

function Forbid-Text {
    param(
        [string]$Path,
        [string]$Text,
        [string]$Reason
    )

    $content = Get-Content -LiteralPath $Path -Raw
    if ($content.Contains($Text)) {
        throw "Forbidden launch safety text found in $Path`: $Reason"
    }
}

function Forbid-Pattern {
    param(
        [string]$Path,
        [string]$Pattern,
        [string]$Reason
    )

    $content = Get-Content -LiteralPath $Path -Raw
    if ($content -match $Pattern) {
        throw "Forbidden launch safety pattern found in $Path`: $Reason"
    }
}

$openxrScript = Join-Path $scriptRoot "start-openxr-retail-sidecar.ps1"
$retailScript = Join-Path $scriptRoot "start-retail-surface-producer.ps1"
$legacyScript = Join-Path $scriptRoot "start-rock-solid.ps1"
$pcvrScript = Join-Path $scriptRoot "start-retail-pcvr-max.ps1"
$commonScript = Join-Path $scriptRoot "fnvxr-sidecar-common.ps1"
$watchExitScript = Join-Path $scriptRoot "watch-retail-exit.ps1"
$readme = Join-Path $Root "README.md"
$cmake = Join-Path $Root "CMakeLists.txt"
$protocolCode = Join-Path $Root "protocol\fnvxr_protocol.h"
$sharedStateCode = Join-Path $Root "protocol\fnvxr_shared_state.h"
$hostCode = Join-Path $Root "host\fnvxr_openxr_pose_host.cpp"
$pluginCode = Join-Path $Root "plugin\fnvxr_nvse_plugin.cpp"
$dinputCode = Join-Path $Root "renderhook\fnvxr_dinput8_proxy.cpp"
$xinputCode = Join-Path $Root "renderhook\fnvxr_xinput_proxy.cpp"
$d3d9Code = Join-Path $Root "renderhook\fnvxr_d3d9_proxy.cpp"
$verifyScript = Join-Path $scriptRoot "verify-fnvxr-proof.ps1"
$oldSmokeScript = Join-Path $scriptRoot (("run-" + "loop" + "back-" + "smoke.ps1"))
$oldTransportDir = Join-Path $Root ("trans" + "port")
$stereoWorldSwitchParam = '[switch]$Enable' + 'StereoWorld'
$stereoWorldRetailArg = '$retailArgs += "-Enable' + 'StereoWorld"'

foreach ($path in @($openxrScript, $retailScript, $legacyScript, $pcvrScript, $commonScript, $verifyScript, $readme, $cmake, $protocolCode, $sharedStateCode, $hostCode, $pluginCode, $dinputCode, $xinputCode, $d3d9Code)) {
    if (-not (Test-Path -LiteralPath $path)) {
        throw "Missing required sidecar path: $path"
    }
}
if (Test-Path -LiteralPath $oldSmokeScript) {
    throw "Stale old-network smoke script must not exist in the shared-memory sidecar launcher set."
}
if (Test-Path -LiteralPath $oldTransportDir) {
    throw "Stale transport directory must not exist in the shared-memory sidecar experiment."
}

