$openxrContent = Get-Content -LiteralPath $openxrScript -Raw
$hostStartIndex = $openxrContent.IndexOf('$hostProcess = Start-Process')
$retailStartIndex = $openxrContent.IndexOf('$fallout = Start-Process')
if ($hostStartIndex -lt 0 -or $retailStartIndex -lt 0 -or $hostStartIndex -gt $retailStartIndex) {
    throw "OpenXR sidecar launcher must start the host before retail."
}

