Require-Text -Path $d3d9Code -Text 'FNVXR_RUN_LOG_DIR' -Reason "D3D9 proxy telemetry must honor the current run directory"
Require-Text -Path $d3d9Code -Text 'forceImmediatePresentation' -Reason "D3D9 proxy must clamp CreateDevice/Reset to immediate presentation"
Require-Text -Path $d3d9Code -Text 'D3DPRESENT_INTERVAL_IMMEDIATE' -Reason "D3D9 proxy must use the explicit immediate present interval"
Require-Text -Path $d3d9Code -Text 'FNVXR_D3D9_FORCE_PRESENT_IMMEDIATE' -Reason "D3D9 immediate presentation clamp must stay controlled by an environment gate"
