Require-Text -Path $d3d9Code -Text 'gNativeSingleTraversalReplayEnabled' -Reason "D3D9 hook must expose the one-traversal/two-eye producer gate"
Require-Text -Path $d3d9Code -Text 'shared stereo disabled; not publishing stereo world frame' -Reason "D3D9 hook must telemeter disabled stereo publishing separately from missing replay draws"
Require-Text -Path $d3d9Code -Text 'fov[0] < -0.01f' -Reason "D3D9 hook must reject zero/placeholder eye FOVs"
