Require-Text -Path $d3d9Code -Text 'FalloutDoRenderFrameAddress = 0x008706B0' -Reason "Native stereo must hook the verified retail full-render boundary"
Require-Text -Path $d3d9Code -Text 'native same-frame stereo pair=' -Reason "Native stereo must telemeter complete left/right pairs and their render time"
Require-Text -Path $d3d9Code -Text 'nativeStereoFirstPersonReady()' -Reason "Native stereo must reject frames until the shared retail camera is positively first person"
Require-Text -Path $d3d9Code -Text 'native stereo gameplay pose origin latched' -Reason "Native stereo must align head and body space at the first accepted gameplay frame"
Require-Text -Path $commonScript -Text 'FNVXR_D3D9_NATIVE_REQUIRE_FIRST_PERSON = "1"' -Reason "Retail native stereo must require strict first-person state"
Require-Text -Path $commonScript -Text 'FNVXR_D3D9_ALLOW_THIRD_PERSON_STEREO = "0"' -Reason "Retail native stereo must never accept third-person camera state"
Require-Text -Path $sharedStateCode -Text 'StereoProducerNativeSameFrame' -Reason "Shared stereo frames must carry native same-frame provenance"
Require-Text -Path $sharedStateCode -Text 'StereoProducerSingleTraversal' -Reason "Shared stereo frames must identify coherent one-traversal/two-eye provenance"
Require-Text -Path $d3d9Code -Text 'fnvxrSingleTraversalStereo' -Reason "D3D9 telemetry must prove one original traversal and the replayed eye draw count"
Require-Text -Path $hostCode -Text 'FNVXR_REQUIRE_NATIVE_STEREO' -Reason "OpenXR host must reject draw-replay pixels in native VR mode"
Require-Text -Path $d3d9Code -Text 'FNVXR_D3D9_STEREO_IDENTICAL_DISARM_FRAMES' -Reason "D3D9 stereo proof must self-disarm after sustained identical left/right frames"
Require-Text -Path $d3d9Code -Text 'eyeViewDelta=' -Reason "D3D9 stereo telemetry must report per-eye matrix delta proof"
Require-Text -Path $d3d9Code -Text 'shouldReplayCurrentDrawToStereo' -Reason "D3D9 hook must filter per-draw UI/HUD calls before stereo replay"
Require-Text -Path $d3d9Code -Text 'screen-space-projection' -Reason "D3D9 hook must reject screen-space projection draws even when stale world view state remains"
Require-Text -Path $d3d9Code -Text 'screen-space-transform' -Reason "D3D9 hook must log rejected screen-space stereo replay draws"
Require-Text -Path $d3d9Code -Text 'user-primitive-draw' -Reason "D3D9 hook must log rejected immediate primitive stereo replay draws"
Require-Text -Path $d3d9Code -Text 'uiSuppressed' -Reason "D3D9 eye-pose telemetry must show when UI mode blocks HMD pose application"
Require-Text -Path $d3d9Code -Text 'screenSpaceProjection' -Reason "D3D9 eye-pose telemetry must show when orthographic UI projection blocks HMD pose application"
Require-Text -Path $d3d9Code -Text 'makeLocalVrEyeView' -Reason "D3D9 eye matrices must compose local VR head/eye offsets without rotating Gamebryo world translation"
Require-Text -Path $d3d9Code -Text 'shared VR body origin latched' -Reason "D3D9 hook must latch a body/world origin from OpenXR pose before applying HMD pose"
Require-Text -Path $d3d9Code -Text 'local VR eye view rejected' -Reason "D3D9 hook must reject exploding head/eye offsets instead of publishing face-locked world views"
Require-Text -Path $d3d9Code -Text 'bodyFrameValid' -Reason "D3D9 eye-pose telemetry must expose whether local VR body frame data is valid"
Require-Text -Path $d3d9Code -Text 'FNVXR_D3D9_GAME_UNITS_PER_METER' -Reason "D3D9 hook must pin the meter-to-Gamebryo-unit conversion"
Require-Text -Path $d3d9Code -Text 'FNVXR_D3D9_POSE_AXIS_MODE' -Reason "D3D9 hook must expose the OpenXR-to-FNV axis conversion mode"
Require-Text -Path $d3d9Code -Text 'xrMetersToGamebryoMeters' -Reason "D3D9 hook must convert OpenXR local meters into FNV/Gamebryo axes"
Require-Text -Path $d3d9Code -Text 'gamebryoRotationFromXrRotation' -Reason "D3D9 hook must convert OpenXR headset rotation into FNV/Gamebryo axes"
Require-Text -Path $d3d9Code -Text 'cameraLocalHeadRotation' -Reason "Native D3D9 stereo must use NiCamera's tested right/up/back local basis instead of actor/world-axis permutations"
Require-Text -Path $d3d9Code -Text 'gravityLevelNativeCameraRotation' -Reason "Native D3D9 stereo must level the camera without replacing its right/up/back column layout"
Require-Text -Path $d3d9Code -Text 'trackedShaderMatrixAt' -Reason "D3D9 hook must patch tracked shader matrix blocks, not only c0-c3"
Require-Text -Path $d3d9Code -Text 'FNVXR_D3D9_SHADER_MATRIX_MAX_CANDIDATES' -Reason "D3D9 hook must support multiple shader matrix candidates per draw"
Require-Text -Path $d3d9Code -Text 'shaderMatrixStartAllowedForStereo' -Reason "D3D9 live shader stereo must reject higher constant blocks that can contain bone matrices"
Require-Text -Path $d3d9Code -Text 'FNVXR_D3D9_SHADER_PATCH_START_REGISTER' -Reason "D3D9 live shader stereo must expose the pinned low-register patch slot"
Require-Text -Path $d3d9Code -Text 'FNVXR_D3D9_SHADER_STEREO_ALLOW_VERTEX_HASHES' -Reason "D3D9 live shader stereo must support opt-in shader hash allowlisting"
Require-Text -Path $d3d9Code -Text 'currentVertexShaderAllowedForStereoPatch' -Reason "D3D9 live shader stereo must check the shader hash allowlist before writing constants"
Require-Text -Path $d3d9Code -Text 'applyShaderSanityOffset' -Reason "D3D9 shader diagnostics must prove whether the live shader constants own the world matrix"
Require-Text -Path $d3d9Code -Text 'FNVXR_D3D9_SHADER_SANITY_SLOT' -Reason "D3D9 shader diagnostics must support c1.w and row-major slot sanity probes"
Require-Text -Path $d3d9Code -Text 'd3d9VrPoseInputEnabled' -Reason "D3D9 hook must not consume OpenXR pose data during fallback quad-only mode"
Require-Text -Path $d3d9Code -Text 'publishIsDiagnosticSnapshot' -Reason "D3D9 hook must mark best separated snapshots as diagnostic-only unless explicitly overridden"
Require-Text -Path $d3d9Code -Text 'header->worldCandidate = (worldCandidate && !publishIsDiagnosticSnapshot && visualCoverageReady) ? 1 : 0' -Reason "Partial draw snapshots and visual warmup frames must not satisfy world-stereo handoff gates"
Require-Text -Path $d3d9Code -Text 'diagnosticSnapshot' -Reason "D3D9 telemetry must expose when a shared stereo frame is only a diagnostic snapshot"
Require-Text -Path $d3d9Code -Text 'Those stale screen-space transforms are not evidence' -Reason "Proof-only shader discovery must not be blinded by Fallout's stale fixed-function screen transforms"
Require-Text -Path $d3d9Code -Text 'auditStereoCollapseAfterDraw' -Reason "D3D9 diagnostics must find the exact draw where separated eye targets collapse"
Require-Text -Path $d3d9Code -Text 'stereo collapse audit frame=' -Reason "D3D9 collapse audit telemetry must include frame/draw/hash/shader state"
Require-Text -Path $d3d9Code -Text 'fingerprintD3DShaderBytecode' -Reason "D3D9 collapse diagnostics must fingerprint shader bytecode instead of unstable COM pointer addresses"
Require-Text -Path $d3d9Code -Text 'learnStereoCollapseShaderPair' -Reason "D3D9 diagnostics must learn shader pairs that collapse separated eye targets"
Require-Text -Path $d3d9Code -Text 'collapse-shader-pair' -Reason "D3D9 replay must skip shader pairs already proven to collapse stereo during a diagnostic run"
Require-Text -Path $d3d9Code -Text 'configured-collapse-shader-pair' -Reason "D3D9 replay must skip pre-proven shader hash pairs without per-draw audit"

$networkForbiddenPaths = @(
    $readme,
    $cmake,
    $protocolCode
) + @(Get-ChildItem -LiteralPath (Join-Path $Root "docs") -Filter "*.md" -File | ForEach-Object { $_.FullName })

foreach ($path in $networkForbiddenPaths) {
    $oldNetworkTerms = @(
        '\b' + 'U' + 'DP' + '\b',
        '\b' + 'u' + 'dp' + '\b',
        '127' + '\.0\.0\.1',
        '490' + '71',
        '490' + '72',
        'Default' + 'Pose' + 'Port',
        'Default' + 'Game' + 'Port',
        'fnvxr_' + 'host_' + 'stub',
        'fnvxr_' + 'plugin_' + 'stub',
        'run-' + 'loop' + 'back-' + 'smoke',
        'transport' + '/'
    )
    Forbid-Pattern -Path $path -Pattern ($oldNetworkTerms -join '|') -Reason "Live bridge docs/code must describe the shared-memory nucleus, not the old network stub."
}

$summary = [ordered]@{
    scriptsChecked = $scripts.Count
    parseErrors = $parseErrors.Count
    openXrHostStartsBeforeRetail = $true
    sidecarProfilesVerified = $true
    osCursorSideChannelsForbidden = $true
    networkStubReferencesForbidden = $true
}
$summary | ConvertTo-Json -Depth 4
